namespace BgControls.Windows.Controls.DragDrop;/// <summary>/// 表示拖动箭头调整事件的参数类./// </summary>public class DragArrowAdjustingEventArgs : CancelRoutedEventArgs{    /// <summary>    /// Initializes a new instance of the <see cref="DragArrowAdjustingEventArgs"/> class.    /// </summary>    /// <param name="routedEvent">路由事件标识.</param>    /// <param name="arrowTransformation">箭头变换组.</param>    public DragArrowAdjustingEventArgs(RoutedEvent routedEvent, TransformGroup arrowTransformation)        : base(routedEvent)    {        // 验证参数是否为空.        ArgumentNullException.ThrowIfNull(arrowTransformation, nameof(arrowTransformation));        // 将参数赋值给属性.        this.ArrowTransformation = arrowTransformation;    }    /// <summary>    /// Gets 箭头变换组.    /// </summary>    public TransformGroup ArrowTransformation { get; }}